form:Form.form:Scripts:
		function Initialize()
{	
	if ((Ctrl("main").GetMode()=="SHOW") || (Ctrl("main").GetMode()=="EDIT"))
	{		
		CtrlEnabled("CLOSE", Ctrl("c_estado").GetXValue()!="C");
		CtrlEnabled("EDIT", Ctrl("c_estado").GetXValue()!="C");
		CtrlEnabled("DELETE", Ctrl("c_estado").GetXValue()!="C");
		CtrlEnabled("ESCUADRAS", Ctrl("d_tipohorario").GetXValue()=="R");
	} else
	if (Ctrl("main").GetMode()=="LIST")
		ChangeSelect(Ctrl("LIST"));

}

function ChangeSelect(lvObj)
{                          
	CtrlEnabled("CLOSE", (lvObj.GetSelectAttrValue("img")?false:true));
	CtrlEnabled("EDIT", (lvObj.GetSelectAttrValue("img")?false:true));
	CtrlEnabled("DELETE", (lvObj.GetSelectAttrValue("img")?false:true));
	CtrlEnabled("ESCUADRAS", (lvObj.GetSelectAttrValue("d_tipohorario")=="R"?true:false));

	Ctrl("id").SetCValue(lvObj.GetSelectAttrValue("id"));
}

function CheckLength(obj)
{
	if ((Ctrl("d_tipohorario").GetXValue()=="F") && (obj.GetXValue()!="7"))
	{             
		obj.SetError("Error el largo los Horarios Fijos es 7.");
		return false;
	} else
	if (Ctrl("d_tipohorario").GetXValue()!="F" && obj.GetXValue()!="" && parseInt(obj.GetXValue())>250)
	{
		obj.SetError("Error el largo de días en Horarios Rotativos o Libres no debe superar los 250.");
		return false;
	}

	return true;
}

function CheckEscuadra(obj)
{
	if ((Ctrl("d_tipohorario").GetXValue()=="R") && (obj.GetXValue()==""))
	{             
		obj.SetError("Debe especificar la cantidad de Escuadras para Horarios Rotativos.");
		return false;
	}	
	return true;
}

function ChangeTYPE(obj)
{
	if (obj.GetXValue()=="F") 
		Ctrl("e_dias").SetXValue("7");
	if (obj.GetXValue()!="R") 
	{ 
		CtrlEnabled("cantesc", false);
		Ctrl('cantesc').SetXValue("0");
	}	
	else
	{
		CtrlEnabled("cantesc", true);  
		Ctrl('cantesc').SetXValue("");
	}
}

function Change()
{
	if (Ctrl("main").GetMode()=="LIST")
		Ctrl('main').DoEvent('AfterDUPLICATE');
}
